with tp as (select id from public.support_programs where slug='kumamoto-kumamoto-air-conditioner-energy'), us as (update public.support_sources src set title='エアコン設置サポート事業について｜社会福祉法人 熊本市社会福祉協議会', official_checked_at='2026-07-01', content_hash='a3VtYW1vdG8ta3VtYW1vdG8tYWlyLWNvbmRpdGlv', source_kind='official', quality_state='ok', review_interval_days=90 from tp where src.support_program_id=tp.id and src.url='https://www.kumamoto-city-csw.or.jp/%E3%82%A8%E3%82%A2%E3%82%B3%E3%83%B3%E8%A8%AD%E7%BD%AE%E3%82%B5%E3%83%9D%E3%83%BC%E3%83%88%E4%BA%8B%E6%A5%AD%E3%81%AB%E3%81%A4%E3%81%84%E3%81%A6/' returning src.id) insert into public.support_sources (support_program_id, url, title, publisher, retrieved_at, official_checked_at, content_hash, notes, source_kind, quality_state, detected_issue_codes, review_interval_days) select tp.id, 'https://www.kumamoto-city-csw.or.jp/%E3%82%A8%E3%82%A2%E3%82%B3%E3%83%B3%E8%A8%AD%E7%BD%AE%E3%82%B5%E3%83%9D%E3%83%BC%E3%83%88%E4%BA%8B%E6%A5%AD%E3%81%AB%E3%81%A4%E3%81%84%E3%81%A6/', 'エアコン設置サポート事業について｜社会福祉法人 熊本市社会福祉協議会', 'www.kumamoto-city-csw.or.jp', now(), '2026-07-01', 'a3VtYW1vdG8ta3VtYW1vdG8tYWlyLWNvbmRpdGlv', 'pilot air-conditioner-energy import', 'official', 'ok', '{}'::text[], 90 from tp where not exists (select 1 from us);

-- municipality_topic_coverage: air-conditioner-energy の調査状況

また障害福祉「補装具の交付・修理について」ページ（https://www.city.saitama.lg.jp/002/003/004/003/006/p001359.html）も再度WebFetchで確認したところ、対象品目は義足・車いす・装具・補聴器・義眼等であり、冷房器具・エアコンは含まれていないことを再確認した。

Google検索経由での追加探索は結果を取得できなかったが（検索結果ページの内容が取得不可）、一次調査で確認済みの主要な公式ページはいずれも一次調査の結論と一致した。第三者サイト（アフィリエ' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;

追加で確認した2つの福祉局ページ（障害児者日常生活用具給付等事業 https://www.city.kawasaki.jp/350/page/0000023034.html 、高齢者住宅改造費助成事業 https://www.city.kawasaki.jp/350/page/0000022587.html ）も到達可能（HTTP 200）だが、いずれもエアコン・冷房器具の購入費助成を明記した記述は見当たらず、対象品目の詳細（別表等）はページ本文に表示されていないため、公式サイト上の記載だけでは市独自のエアコン購入費助成制度の存在を確認できない。これは一次調査のresearchNoteに記載された「区役所高齢・障害課への確認が必要」という留保と整合する。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='kawasaki' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;

検証手順：
1. evidenceUrl（相模原市公式FAQページ）をWebFetchで直接取得し内容を確認。「令和5年度には国の物価高騰対策交付金を用いてエアコン等家電・給湯器の買い替え補助制度を実施していたが、現在（確認時点）は省エネルギー対策を目的とした家電及び給湯器等に対する補助制度は実施していない」と市が明示していることを確認した。これは一般市民向けの単年度事業であり、かつ現在終了している点でも一次調査の記述と一致する。
2. 相模原市の補助制度一覧ページ（環境部門）をWebFetchで確認。エネルギー関係の補助メニューに高齢者・障害者向けの熱中症予防エアコン購入費助成に該当する制度は掲載されていない。
3. 相模原市の障害者福祉制度案内ページをWebFetchで確認。エアコン購入費助成・日常生活用具給付でのエアコン関連の言及は見当たらない（詳細な品目一覧ページの直接確認は404で不可だったが、案内ページ自体に該当制度への導線は無い）。

以上より、高齢者・障害者・低所得/要援護世帯を対象とした相模原市独自の「エアコン購入費等助成」' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='sagamihara' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;

追加検証内容：
1. 浜松市公式サイトの在宅福祉サービス一覧ページ（kourei/welfare/elderly/zaitaku/index.html）をWebFetchで再確認。エアコン購入費・設置費・熱中症対策関連の記述・リンクは一切なし（短期宿泊、緊急通報、配食、紙おむつ、住宅改造費補助等のみ掲載）。
2. site:city.hamamatsu.shizuoka.jp でのエアコン購入費助成の検索では、家庭向け福祉制度は一切ヒットせず、ヒットするのは全て事業者向け省エネ設備補助金（浜松市省エネ設備導入事業費補助金、脱炭素経営設備導入支援事業＝高効率空調の業務用補助、しかも高効率空調・高効率照明の受付は令和7年6月16日で終了）のみ。これらは家庭用エアコン購入費助成とは性質が異なり、対象外。
3. 一次調査で「AI要約が言及していた」浜松市の福祉的エアコン購入費助成（65歳以上のみ非課税世帯、上限5万円、地域包括ケア推進課054-626-1117）に' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='hamamatsu' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
