insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kumamoto' and m.slug = 'kumamoto'), 'kumamoto-kumamoto-air-conditioner-energy', 'エアコン設置サポート事業（熊本市社会福祉協議会）', '熊本市に在住し、高齢、障がいや持病等により体温の調整機能に配慮が必要な方を対象に、熱中症事故等を防ぐため新品エアコン（6畳用）の設置を行う事業。熊本市社会福祉協議会が実施しています。', NULL, 'subsidy', '熊本市在住で、高齢、障がいや持病等により体温の調整機能に配慮が必要な方が対象となる可能性があります。所得要件など詳細条件は公式チラシ・申請書での確認が必要です。', '新品エアコン（6畳用）の設置。具体的な助成上限額・自己負担の有無はページ本文に明記されておらず、公式チラシでの確認が必要です。', '受付期間の記載はページ本文になく、公式チラシ・窓口での確認が必要です。', '「エアコン設置サポート事業申請書兼同意書」を熊本市社会福祉協議会または各区事務所へ提出する方法とみられます。詳細は公式チラシ・各区社協窓口でご確認ください。', 'エアコン設置サポート事業申請書兼同意書、その他必要書類（詳細は公式チラシ参照）', FALSE, '社会福祉法人 熊本市社会福祉協議会', '', 'https://www.kumamoto-city-csw.or.jp/%E3%82%A8%E3%82%A2%E3%82%B3%E3%83%B3%E8%A8%AD%E7%BD%AE%E3%82%B5%E3%83%9D%E3%83%BC%E3%83%88%E4%BA%8B%E6%A5%AD%E3%81%AB%E3%81%A4%E3%81%84%E3%81%A6/', 'https://www.kumamoto-city-csw.or.jp/%E3%82%A8%E3%82%A2%E3%82%B3%E3%83%B3%E8%A8%AD%E7%BD%AE%E3%82%B5%E3%83%9D%E3%83%BC%E3%83%88%E4%BA%8B%E6%A5%AD%E3%81%AB%E3%81%A4%E3%81%84%E3%81%A6/', 'エアコン設置サポート事業について｜社会福祉法人 熊本市社会福祉協議会', '2026-07-01', 'medium', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'applicationMethodText', 'requiredDocumentsText', 'contactPhone']::text[], '本制度は熊本市社会福祉協議会（準公式・許可ドメイン）による情報に基づきます。所得要件・助成上限額・受付期間などの詳細はページ本文に明記がなく、公式チラシまたは熊本市社会福祉協議会・各区事務所へ直接ご確認ください。申請すれば必ず受給できるものではなく、審査・予算枠の状況により異なります。', 'review', NULL, now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'kumamoto-kumamoto-air-conditioner-energy' and c.slug = 'nursing-care' on conflict do nothing;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'kumamoto-kumamoto-air-conditioner-energy' and c.slug = 'disability' on conflict do nothing;
insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'kumamoto-kumamoto-air-conditioner-energy' and le.slug = 'caregiving' on conflict do nothing;
insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'kumamoto-kumamoto-air-conditioner-energy' and le.slug = 'disability' on conflict do nothing;
insert into public.support_program_topics (support_program_id, support_topic_id) select sp.id, t.id from public.support_programs sp, public.support_topics t where sp.slug = 'kumamoto-kumamoto-air-conditioner-energy' and t.slug = 'air-conditioner-energy' on conflict do nothing;
insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"kumamoto-kumamoto-air-conditioner-energy","status":"review","title":"エアコン設置サポート事業（熊本市社会福祉協議会）","officialUrl":"https://www.kumamoto-city-csw.or.jp/%E3%82%A8%E3%82%A2%E3%82%B3%E3%83%B3%E8%A8%AD%E7%BD%AE%E3%82%B5%E3%83%9D%E3%83%BC%E3%83%88%E4%BA%8B%E6%A5%AD%E3%81%AB%E3%81%A4%E3%81%84%E3%81%A6/","topic":"air-conditioner-energy"}'::jsonb, 'pilot:kumamoto-kumamoto-air-conditioner-energy:a3VtYW1vdG8ta3VtYW1vdG8tYWlyLWNvbmRpdGlv' from public.support_programs sp where sp.slug='kumamoto-kumamoto-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.sapporo.jp/fukushi-guide/seikatuhogo.html', '一次調査の結論を追加検証し、妥当と判断した。\n\n検証内容:\n1. evidenceUrl（https://www.city.sapporo.jp/fukushi-guide/seikatuhogo.html）をWebFetchで再確認 — 生活保護制度の概要ページであり、エアコン（冷房機器）購入費・設置費助成に関する具体的な記載（対象要件・金額上限等）は無いことを確認。「家具、電化製品等の更新費などの費用」という一般的記載があるのみで、クーラー等購入費支給の制度詳細ページとしては機能していない。\n2. WebSearch（site:city.sapporo.jp、エアコン 購入費 助成 熱中症）で追加探索したが、ヒットしたのはいずれも一次調査で既に確認・除外済みの制度のみ：\n   - 省エネ機器エネルギー源転換補助金制度／再エネ省エネ機器導入補助金制度（環境局所管、灯油暖房からの転換・脱炭素目的、全市民対象で福祉的対象要件なし）\n   - 市民集会施設エアコン設置補助金（集会施設向け、個人世帯向けではない）\n   - クーリングシェルター（避暑施設の案内であり、購入費助成' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hokkaido' and m.slug='sapporo' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.sendai.jp/ondanka/syoene/shoene_kuucho_kyuto_previiew.html', '一次調査（仙台市公式サイトの複数切り口での調査）を敵対的に再検証した。evidenceUrlのページをWebFetchで直接確認したところ、これは「仙台市省エネ空調・給湯転換補助金」であり、既存の灯油暖房・給湯設備を撤去して寒冷地エアコン等（上限15万円）やエコキュート等へ転換する個人向けの省エネ・地球温暖化対策事業である。対象は全世帯（灯油設備を撤去する条件付き）であり、高齢者・障害者・低所得/要援護世帯限定の熱中症予防目的助成ではない。制度趣旨・対象要件がトピック（エアコン購入費助成＝熱中症予防・要援護者向け）と一致しないため、この制度をfoundとして採用するのは不適切であり、一次調査の判断（not_found_on_official_site、参考情報としてevidenceUrl提示）は妥当と判断した。\n\nなお一次調査が確認した他の関連制度（障害者日常生活用具給付事業にエアコンが対象品目として含まれない点、生活保護のエアコン購入費支給が国制度の運用である点）についても、仙台市独自のエアコン購入費助成事業ページは見当たらないとの結論を支持する。programは提示しない（co' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='miyagi' and m.slug='sendai' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.saitama.lg.jp/001/009/015/010/002/index.html', '再検証のためevidenceUrl（さいたま市公式サイトの補助金情報一覧ページ、.lg.jpドメインで許可ホスト要件を満たす）をWebFetchで実際に取得し、内容を確認した。掲載されている補助金は「令和8年度 省エネ・断熱住宅普及促進補助金」（住宅の断熱・省エネ機器設置費補助、対象者を高齢者等に限定しない一般制度）と「令和8年度さいたま市電気自動車等普及促進対策補助金」の2件のみで、高齢者・障害者・低所得世帯向けのエアコン購入費・設置費助成は掲載されていないことを確認した。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/jiritsu/nichigu.html', '一次調査（city.chiba.jpを中心に「エアコン 助成」「高齢者 冷房機器 購入 設置 補助金」「障害者 日常生活用具 冷房」「生活保護 熱中症対策 エアコン設置費 助成」等で複数回検索）を追加実施し、一次調査の結論（千葉市独自のエアコン購入費助成制度は公式サイト上で確認できない＝not_found_on_official_site）を支持する結果を得た。\n\n追加確認事項：\n1. WebFetchで一次調査のevidenceUrl（暑さ対策ページ）を再検証＝エアコン助成の記載なし、熱中症予防の一般的呼びかけのみ。not_found時のevidenceとしては不適切なため、日常生活用具費支給ページ（city.chiba.jp/hokenfukushi/koreishogai/jiritsu/nichigu.html）に差し替えた。\n2. 障害者向け日常生活用具費支給の対象品目別表PDF（1_7_2shougaishanichiguyoukou.pdf）を直接確認しようとしたが404で取得不可。ページ本文の要約では、列挙されたカテゴリ（介護訓練支援用具・自立生活支援用具・在宅' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.yokohama.lg.jp/kurashi/machizukuri-kankyo/ondanka/etc/ecohama.html', '一次調査のnot_found_on_official_site判定を検証し妥当と確認した。evidenceUrlはWebFetchで直接到達可能、横浜市公式ドメイン(city.yokohama.lg.jp)で許可ホストに該当。ただし当該ページの「エコハマ（横浜市エコ家電応援キャンペーン）」は(1)対象が高齢者・障害者・低所得世帯限定ではなく全市民向けの省エネ促進策であり、福祉的エアコン購入費助成の要件を満たさない、(2)公式ページ本文に「令和8年4月7日現在、令和8年度の実施予定はございません」と明記され現在受付終了・次年度も未定であることをWebFetchで再確認した。二重の理由でこの制度は対象外である。WebSearchでも「横浜市では現在、一般個人向けのエアコン購入費用助成金制度は実施されていません」との民間まとめ情報が複数あり(事業者向け省エネルギー化支援助成金や、他自治体の高齢者向け助成事例との混同を指摘する記事も含む)、横浜市独自の高齢者・障害者・低所得世帯向けエアコン購入費助成制度の存在を裏付ける公式情報は見つからなかった。一次調査が対象外と判断した日常生活用具給付・生活' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='yokohama' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.kawasaki.jp/templates/faq/300/0000155333.html', '一次調査の結論を検証・確認した。evidenceUrl（川崎市公式FAQ、city.kawasaki.jpドメイン、HTTP 200到達可）を再取得したところ、「川崎市では省エネタイプの家電製品の購入に対する補助は行っておりません」と明記されており、エアコン購入に関する具体的な助成制度への言及もない。一次調査の記述と完全に一致する。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.sagamihara.kanagawa.jp/shisei/1026875/faq/gomi/1033977.html', '一次調査の判定を検証し、妥当と確認した。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.niigata.lg.jp/kurashi/shimin/koeki_index/setsubiseibihojyo.html', 'WebFetchでevidenceUrlを直接検証した。ページ内容は「新潟市設備整備補助」で、対象は自治会・町内会・地域コミュニティ協議会等の団体（集会所備品としてのエアコン等）であり、個人住宅用エアコンの購入・設置費用への補助についての記載は一切ない。一次調査の結論（新潟市には個人向けエアコン購入費助成制度が公式サイト上で確認できない）を裏付ける結果であり、coverage=not_found_on_official_siteは妥当と判断した。program（制度データ）は生成しない。検討段階とされる『高齢者向け暑熱対策支援事業』（2026年度予算化の可能性）は未確定情報のため掲載を見送った。今後、新潟市が制度を新設した場合は再調査が必要。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='niigata' and m.slug='niigata' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.shizuoka.lg.jp/s2835/faq/s000003.html', '一次調査の結論を再検証のうえ支持する。公式FAQページ(city.shizuoka.lg.jp、環境局GX推進課政策係054-221-1611)をWebFetchで再確認したところ、「現状、省エネ家電への補助金を設けることは予定しておりません」と明記されており、令和4年度の補助事業は終了済みであることが確認できた。さらに静岡市の日常生活用具給付関連ページ(s5498/s002816.html)を追加確認したが、対象品目は特殊寝台・特殊マット・入浴補助用具・視覚障害者用時計等に限定され、エアコンや冷房機器への言及は一切ない。s009750.html(支援制度・補助金一覧)は404で当該URLが存在しなかった(一次調査時点のURL構成と現況が変化した可能性、またはURL誤りの可能性がある)。地域包括ケア推進課(054-626-1117)・障害福祉課(054-626-1127)を窓口とする具体的な助成制度(上限5万円等)は、一次調査が指摘した通りWebSearchのAI要約による他自治体情報(港区・南魚沼市・愛南町等)とのハルシネーション混同であり、静岡市公式サイト上でこれを裏付けるページは' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='shizuoka' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/index.html', '一次調査のcoverage=not_found_on_official_siteを追加検証し、妥当と判断した（ok=true）。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'needs_review', '2026-07-01', 'https://www.city.nagoya.jp/kenkofukushi/page/0000183804.html', '検証のためevidenceUrlをWebFetchで再取得し確認。ページタイトルは「【受付終了】名古屋市在宅高齢者エアコン設置等助成事業」、本文冒頭に「本事業は、令和7年9月30日をもって、受付を終了しました。」と明記。対象は名古屋市在住・確認日基準65歳以上・市民税非課税世帯等（生活保護受給世帯含む）・世帯でエアコン未所有・過去に同助成未受給。助成額上限92,000円（税込、購入費・設置工事費または修理費）。受付期間は令和7年4月1日〜9月30日の単年度事業。令和8年度の再実施告知は公式サイト上に確認できず。検証基準(d)「過年度のみ/受付終了でない」を満たさないため、一次調査の判断どおりneeds_reviewを維持し、programは作成しない。evidenceUrlは名古屋市公式ドメイン(city.nagoya.jp)で当該助成事業ページそのものであり、導線としては妥当。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='aichi' and m.slug='nagoya' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.kyoto.lg.jp/hokenfukushi/page/0000280828.html', '一次調査の結論（京都市には高齢者・障害者・低所得世帯等を対象とした市独自の「エアコン購入費等の助成」制度は公式サイト上で確認できない）を検証した。officialUrlをWebFetchで再取得し、(a)到達可能 (b)city.kyoto.lg.jpの許可ホスト (c)京都市公式ページであることを確認。ただしこのページ（日常生活用具給付事業＝重度障害者向け）の本文テキストにはエアコン・冷房・扇風機への言及がなく、一次調査の記述と一致した。給付対象品目一覧はPDFのため直接URLでの取得を試みたが404で失敗し、PDF内の品目名までは確認できなかった（一次調査と同じ制約）。\n\nまた、一次調査が「非該当」と判定した省エネ家電買換え促進事業（環境政策局）も再確認したところ、対象は「京都市内に所在する住宅に自ら居住する方」で市民全般が対象であり、高齢者・障害者・低所得者等への対象限定はなく、福祉目的の対象限定エアコン購入助成という本トピックの定義には該当しないとの一次調査の判断は妥当と確認した（申請期限は令和9年3月15日で受付中だが、これは福祉制度ではないため対象外）。\n\n以上より' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kyoto' and m.slug='kyoto' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.osaka.lg.jp/kankyo/page/0000197072.html', '一次調査の結論（大阪市独自のエアコン本体購入・設置費用を対象とする一般助成制度は大阪市公式サイト上で確認できない＝not_found_on_official_site）は、追加のWeb検索（「大阪市 エアコン 購入 助成 高齢者」「大阪市 熱中症予防 エアコン 補助金」等）でも覆らず、妥当と判断した。近隣他市（門真市・泉大津市・大東市・和泉市等）には省エネエアコン買い替え補助が存在するが、大阪市には見当たらない。一方、一次調査で提示されたevidenceUrl自体をWebFetchで検証したところ、HTTP 404 Not Foundが返り、現在アクセスできないことが判明した。検索エンジンのインデックスには同URLに対応するページタイトル「大阪市生活保護等世帯空気調和機器稼働費補助金交付要綱」が残っているため、大阪市がページを移転・改廃した可能性が高い。coverageの判定自体は妥当だが、evidenceUrlはリンク切れであり、公開時には差し替えまたは無効化の注記が必要。programはfoundではないため生成していない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='osaka' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.sakai.lg.jp/kurashi/gomi/ondanka/oshirase/hojokin_shien/index.html', '一次調査のnot_found_on_official_site判定を検証し妥当と確認した。(1) evidenceUrl(補助金・支援制度一覧)をWebFetchで再確認: 掲載されているのは事業所向け再エネ電力利用促進事業・事業所向け省エネ設備等導入支援事業補助金・堺市スマートハウス化等支援事業・堺市ZEH支援事業のみで、個人向け（特に高齢者・障害者・低所得世帯向け）エアコン購入費・設置費助成は掲載なし。(2) WebSearchで「堺市 エアコン購入費 助成 高齢者 site:city.sakai.lg.jp」を実行し、ヒットした公式ページ(生活保護のエアコン購入費/対象の省エネ家電の購入=堺エコライフポイント/日常生活用具/事業所向け補助金各種/国の補助制度案内)はいずれも一次調査で既に確認・除外済みの制度と一致（現金給付や購入費補助ではないポイント制度、特別事情限定の生活保護家具什器費、対象品目にエアコンを含まない日常生活用具給付、事業所向け補助金）。(3) 非公式まとめサイト「サカイノワ」が示唆する「3制度」についても再検索したが、内容は堺エコライフポイント・生活保護特別事情' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='sakai' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.kobe.lg.jp/a01110/hojokin.html', '検証完了。evidenceUrl（https://www.city.kobe.lg.jp/a01110/hojokin.html）をWebFetchで直接確認：正規の神戸市公式ホスト（city.kobe.lg.jp）に到達し、ページ内容は「住宅支援や補助金など」の一覧（バリアフリー改修助成・耐震化・断熱化・空き家対策等）でエアコン購入費・設置費助成の記載は一切なし。追加でWebSearch（site:city.kobe.lg.jp、エアコン購入費助成 高齢者）を実施したが、ヒットしたのは(1)神戸市省エネ設備更新補助金＝中小企業・中堅企業向けの事業者向け省エネ設備更新補助（対象外・エアコン家庭向けではない）、(2)地球温暖化に関する補助金（個人向け）＝一般省エネ家電施策、(3)住宅改修助成事業＝高齢者・障害者向けバリアフリー改修（エアコンではなく住宅改修）、(4)補装具費の支給＝障害者向け補装具（日常生活用具のエアコンとは別カテゴリ）のみで、いずれも神戸市独自の高齢者・障害者・低所得世帯向けエアコン購入費助成には該当しない。一次調査のresearchNoteの内容（4ページの確認結果、' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.okayama.jp/kurashi/category/1-16-4-6-0-0-0-0-0-0.html', '一次調査(coverage=not_found_on_official_site)を独立して再検証した。(1)提示されたevidenceUrl(生活保護制度についてページ)をWebFetchで実際に確認したところ、ページ内容はタイトル「生活保護制度について」、生活保護の手引き・Q&A・福祉事務所窓口一覧のみで、エアコン購入費・設置費助成への言及は皆無だった。エビデンスとして薄弱なため、より関連性の高い岡山市公式「補助金・助成金」カテゴリページに差し替えを推奨する。(2)そのカテゴリページもWebFetchで確認したが、エアコン購入費助成制度へのリンクは掲載されていなかった。(3)WebSearchで「岡山市 エアコン 購入費 助成 高齢者 熱中症」「site:city.okayama.jp エアコン 設置費用 補助」等を検索したが、ヒットしたのはいずれも岡山市独自の脱炭素・省エネ目的の全市民/事業者向け制度(住宅用/事業所用スマートエネルギー導入促進補助事業、省エネ機器更新緊急支援補助金)のみで、高齢者・障害者・低所得者を対象とした熱中症予防目的の市独自エアコン購入費助成制度は確認でき' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='okayama' and m.slug='okayama' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014921/1006099/1025781/1022187.html', '一次調査のevidenceUrlをWebFetchで直接検証した。当該ページは「日常生活用具の給付」制度であり、対象は重度障害者(児)・知的障害者(児)・精神障害者(児)・難病患者等、給付用具は特殊寝台・入浴補助用具・点字器・人工喉頭・ストマ用装具・紙おむつ等で、エアコン（冷房機器）は給付対象用具に含まれていないことを確認した。これは一次調査の記述（①高齢者日常生活用具給付は自動消火器・電磁調理器が対象で冷房機器は対象外）と整合する。さらに広島市公式トップページを確認したが、エアコン購入費・設置費助成や熱中症対策の家電購入補助への直接リンクは見当たらず、「熱中症にならないための対策」という一般的な注意喚起ページへの案内があるのみだった。以上より、広島市（政令指定都市本体）には市独自のエアコン購入費助成制度が公式サイト上で確認できないという一次調査の結論（not_found_on_official_site）は妥当と判断する。programは提供しない（coverage=not_found_on_official_siteのため該当なし）。念のため、福祉事務所や区役所への直接確認、または' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.kitakyushu.lg.jp/kurashi/menu01_0367.html', '一次調査の結論を独立に再検証した。(1) 一次調査が提示したevidenceUrl（90000700.html）をWebFetchで確認したところ、熱中症予防の一般啓発情報のみで、エアコン購入費・設置費助成制度への言及は皆無だった。文脈的にevidenceとして不適切なため、北九州市公式の「補助制度・税制」一覧ページ（https://www.city.kitakyushu.lg.jp/kurashi/menu01_0367.html）に差し替えた。同ページは住宅耐震改修補助・転入世帯向け情報等を掲載するが、エアコン関連の助成制度は一切掲載されておらず、「制度一覧に存在しない」という結論をより強く支持する。(2) 一次調査が言及した内部PDF（001093661.pdf、生活保護利用者及び低所得者へのエアコン設置）を独立に再取得したが、やはりテキスト抽出不能（破損/画像ベース等）で、内容を確認できなかった。一般公開の制度ページとしての体裁も確認できず、確証材料として採用不可という一次調査の判断は妥当。(3) Web検索でも、2026年度（令和8年度）時点で北九州市独自の個人向けエアコン購' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='kitakyushu' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'needs_review', '2026-07-01', 'https://www.city.fukuoka.lg.jp/kankyo/s-suishin/hp/syoenekaden2026.html', '再調査の結果、一次調査の『福岡市に該当制度なし』という結論は誤りと判明。福岡市は令和8年度（2026年度）に『省エネ家電買い換え促進事業（国の重点支援地方交付金活用事業）』を実施予定で、対象家電にエアコン（2027年基準）と冷蔵庫（2021年基準）が含まれる。所管は環境局脱炭素社会推進部脱炭素社会推進課（TEL 092-711-4282）。\n\nただし2点、found認定を保留する理由がある。第一に、対象者は福岡市内居住・市税滞納なしのみで、年齢・所得・障害等の属性限定がなく、目的も『脱炭素・省エネ促進』であり、当初想定していた『高齢者・障害者・低所得世帯向け熱中症予防エアコン助成』とは制度趣旨が異なる（対象品目も買い換えのみに限定）。第二に、2026年7月1日時点で申請受付はまだ開始しておらず、『令和8年8月上旬』受付開始予定・申請方法の詳細は『7月中旬公開予定』という準備中の告知段階であり、要件・上限額が今後変更される可能性を否定できない。\n\nこのため、公式ページの存在自体は確認できたが、（a）対象者像がカテゴリの想定と異なる可能性、（b）受付開始前で内容未確定、という2つの' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='fukuoka' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.kumamoto-city-csw.or.jp/%E3%82%A8%E3%82%A2%E3%82%B3%E3%83%B3%E8%A8%AD%E7%BD%AE%E3%82%B5%E3%83%9D%E3%83%BC%E3%83%88%E4%BA%8B%E6%A5%AD%E3%81%AB%E3%81%A4%E3%81%84%E3%81%A6/', 'WebFetchでofficialUrlを再検証。ページは到達可能（社協公式、2024-10-15更新表示）。実施主体は「社会福祉法人 熊本市社会福祉協議会」で、対象は熊本市在住かつ「高齢、障がいや持病等により体温の調整機能に配慮が必要な方」、内容は新品エアコン（6畳用）の設置。申請方法・受付期間・所得要件・自己負担額・助成上限額はページ本文に明記がなく、チラシ・申請書側にある可能性がある旨を確認——一次調査のuncertainFields/disclaimerNoteの記載と一致する。ホスト www.kumamoto-city-csw.or.jp は app/lib/data/quality.ts の EXTRA_ALLOWED_HOSTS に明示登録済みで許可ホスト判定は正しい。city.kumamoto.jp（熊本市公式）上に高齢者・障害者向けエアコン設置助成に相当するページが無いことは一次調査で確認済みであり、市の省エネ家電補助（全市民対象・環境施策）とも正しく区別されている。単年度打ち切りの兆候やページ削除・受付終了の明示は無し。国/都道府県制度との誤認、対象の一部を全体化、' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kumamoto' and m.slug='kumamoto' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
